import{_ as e,o as d,c as a,ae as r}from"./chunks/framework.Czhw_PXq.js";const m=JSON.parse('{"title":"Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"guide/deployment/configuration.md","filePath":"guide/deployment/configuration.md"}'),o={name:"guide/deployment/configuration.md"};function i(s,t,c,n,l,b){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>All Hub services are configured via environment variables, managed by <code>envix</code> through each service&#39;s <code>ConfigModule</code>.</p><h2 id="common-variables" tabindex="-1">Common Variables <a class="header-anchor" href="#common-variables" aria-label="Permalink to &quot;Common Variables&quot;">​</a></h2><p>These variables are shared across all services:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>PORT</code></td><td>No</td><td>HTTP server port (default varies by service)</td></tr><tr><td><code>AUTHUP_URL</code></td><td>Yes</td><td>Authup identity provider URL</td></tr><tr><td><code>REDIS_URL</code></td><td>No</td><td>Redis connection URL (for pub/sub and caching)</td></tr><tr><td><code>AMQP_URL</code></td><td>No</td><td>RabbitMQ connection URL</td></tr></tbody></table><h2 id="database-variables" tabindex="-1">Database Variables <a class="header-anchor" href="#database-variables" aria-label="Permalink to &quot;Database Variables&quot;">​</a></h2><p>Used by <code>server-core</code>, <code>server-storage</code>, and <code>server-telemetry</code>:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>DB_TYPE</code></td><td>Yes</td><td><code>mysql</code>, <code>postgres</code>, or <code>better-sqlite3</code></td></tr><tr><td><code>DB_HOST</code></td><td>Yes*</td><td>Database hostname</td></tr><tr><td><code>DB_PORT</code></td><td>Yes*</td><td>Database port</td></tr><tr><td><code>DB_USERNAME</code></td><td>Yes*</td><td>Database username</td></tr><tr><td><code>DB_PASSWORD</code></td><td>Yes*</td><td>Database password</td></tr><tr><td><code>DB_DATABASE</code></td><td>Yes</td><td>Database name (or <code>:memory:</code> for SQLite)</td></tr></tbody></table><p>*Not required for SQLite.</p><h2 id="storage-variables-server-storage" tabindex="-1">Storage Variables (server-storage) <a class="header-anchor" href="#storage-variables-server-storage" aria-label="Permalink to &quot;Storage Variables (server-storage)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>MINIO_ENDPOINT</code></td><td>Yes</td><td>MinIO/S3 endpoint URL</td></tr><tr><td><code>MINIO_ACCESS_KEY</code></td><td>Yes</td><td>S3 access key</td></tr><tr><td><code>MINIO_SECRET_KEY</code></td><td>Yes</td><td>S3 secret key</td></tr><tr><td><code>MINIO_USE_SSL</code></td><td>No</td><td>Enable SSL for MinIO connection</td></tr><tr><td><code>MINIO_PORT</code></td><td>No</td><td>MinIO port</td></tr></tbody></table><h2 id="telemetry-variables-server-telemetry" tabindex="-1">Telemetry Variables (server-telemetry) <a class="header-anchor" href="#telemetry-variables-server-telemetry" aria-label="Permalink to &quot;Telemetry Variables (server-telemetry)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>VICTORIA_LOGS_URL</code></td><td>Yes</td><td>VictoriaLogs endpoint URL</td></tr></tbody></table>',13)])])}const u=e(o,[["render",i]]);export{m as __pageData,u as default};
